parameters.text:
=Predict the no-show risk for this patient appointment:

- Patient Name: {{ $json['Patient Name'] }}
- Appointment Date: {{ $json['Appointment Date'] }}
- Appointment Time: {{ $json['Appointment Time'] }}
- Appointment Type: {{ $json['Appointment Type'] }}
- Previous No-Shows: {{ $json['Previous No-Shows'] }}
- Booking Channel: {{ $json['Booking Channel'] }}
- Insurance Type: {{ $json['Insurance Type'] }}

Risk score rules:
- 0–39 = low risk
- 40–69 = medium risk
- 70–100 = high risk

Return ONLY this JSON object, nothing else:
{
  "risk_score": <integer 0-100>,
  "risk_level": "<low | medium | high>",
  "reason": "<one sentence explanation>"
}

parameters.jsCode:
const raw = $input.first().json.text || $input.first().json.content?.[0]?.text || '{}';
let parsed;
try {
  parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) {
  parsed = { risk_score: 50, risk_level: 'medium', reason: 'parse error' };
}
return [{ json: { ...parsed, patient: $('Appointment Booked (n8n Form)').first().json } }];

